const H = 1863
const VB = '0 0 820 1863'

function hexToRgb(hex) {
  const m = hex.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i)
  return m ? { r: parseInt(m[1], 16), g: parseInt(m[2], 16), b: parseInt(m[3], 16) } : { r: 16, g: 185, b: 129 }
}

function darkenHex(hex, pct = 0.5) {
  const { r, g, b } = hexToRgb(hex)
  return `rgb(${Math.round(r * (1 - pct))},${Math.round(g * (1 - pct))},${Math.round(b * (1 - pct))})`
}

/**
 * Body water animation (hydration-style): SVG body clip, rising water with gradient,
 * wave, foam, shimmer, bubbles; outline stroke; center content for score.
 */
export default function BodyOutline({
  gender = 'male',
  width = 200,
  height = 440,
  waterLevel = 0,
  waterColor = '#10b981',
  centerContent = null,
  className = '',
  style = {},
}) {
  const clipId = useId().replace(/:/g, '') || 'bodyClip'
  const gradId = useId().replace(/:/g, '') || 'waterGrad'
  const glossId = useId().replace(/:/g, '') || 'bodyGloss'
  const pct = Math.max(0, Math.min(1, waterLevel))
  const translateY = H * (1 - pct)
  const darkColor = darkenHex(waterColor, 0.55)

  return (
    <div
      className={`body-outline-wrap body-outline-svg-wrap ${className}`.trim()}
      style={{ width, height, position: 'relative', ...style }}
    >
      <svg
        viewBox={VB}
        width="100%"
        height="100%"
        preserveAspectRatio="xMidYMid meet"
        className="body-outline-svg"
        aria-hidden
      >
        <defs>
          <clipPath id={clipId}>
            <path d={BODY_PATH} />
          </clipPath>
          {/* Glossy background: soft highlight at top, dark at bottom */}
          <linearGradient id={glossId} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#2a3548" stopOpacity="0.5" />
            <stop offset="4%" stopColor="#1a2332" stopOpacity="1" />
            <stop offset="18%" stopColor="#0f1620" stopOpacity="1" />
            <stop offset="100%" stopColor="#080f18" stopOpacity="1" />
          </linearGradient>
          <linearGradient id={gradId} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={waterColor} stopOpacity="0.92" />
            <stop offset="45%" stopColor={waterColor} stopOpacity="0.85" />
            <stop offset="100%" stopColor={darkColor} stopOpacity="1" />
          </linearGradient>
          <linearGradient id={`${gradId}-shimmer`} x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor="white" stopOpacity="0" />
            <stop offset="50%" stopColor="white" stopOpacity="0.35" />
            <stop offset="100%" stopColor="white" stopOpacity="0" />
          </linearGradient>
        </defs>

        <g clipPath={`url(#${clipId})`}>
          <rect x="0" y="0" width="820" height={H} fill={`url(#${glossId})`} />
        </g>

        <g clipPath={`url(#${clipId})`}>
          <g transform={`translate(0,${translateY})`}>
            <rect x="0" y="0" width="820" height={H} fill={`url(#${gradId})`} />
            <path fill={`${waterColor}99`}>
              <animate
                attributeName="d"
                dur="2.2s"
                repeatCount="indefinite"
                values="M0,0 C137,-36 273,36 410,0 C547,-36 683,36 820,0 L820,1863 L0,1863 Z;M0,0 C137,36 273,-36 410,0 C547,36 683,-36 820,0 L820,1863 L0,1863 Z;M0,0 C137,-36 273,36 410,0 C547,-36 683,36 820,0 L820,1863 L0,1863 Z"
              />
            </path>
            <path fill={`${waterColor}38`}>
              <animate
                attributeName="d"
                dur="2.2s"
                repeatCount="indefinite"
                values="M0,18 C137,-18 273,52 410,18 C547,-18 683,52 820,18 L820,70 L0,70 Z;M0,18 C137,52 273,-18 410,18 C547,52 683,-18 820,18 L820,70 L0,70 Z;M0,18 C137,-18 273,52 410,18 C547,-18 683,52 820,18 L820,70 L0,70 Z"
              />
            </path>
            <rect x="20" y="8" width="780" height="18" rx="9" fill={`url(#${gradId}-shimmer)`}>
              <animate attributeName="opacity" dur="2.5s" values="0.9;0.1;0.9" repeatCount="indefinite" />
            </rect>
            {[200, 420, 620, 310, 560, 155, 680].map((cx, i) => (
              <circle key={i} cx={cx} r={[12, 9, 15, 7, 11, 6, 8][i]} fill={`${waterColor}aa`}>
                <animate attributeName="cy" from="1700" to="-100" dur={`${5 + i * 0.5}s`} repeatCount="indefinite" begin={`${i * 0.3}s`} />
                <animate attributeName="opacity" values="0;0.8;0.8;0" dur={`${5 + i * 0.5}s`} repeatCount="indefinite" begin={`${i * 0.3}s`} />
              </circle>
            ))}
          </g>
        </g>

        {/* Score clipped to body outline so it doesn’t spill outside */}
        {centerContent != null && (
          <g clipPath={`url(#${clipId})`}>
            <foreignObject x="0" y="0" width="820" height={H}>
              <div
                xmlns="http://www.w3.org/1999/xhtml"
                style={{ position: 'relative', width: '100%', height: '100%' }}
              >
                <div
                  className="body-outline-center body-outline-center-clipped"
                  style={{
                    position: 'absolute',
                    left: '50%',
                    top: '22%',
                    transform: 'translate(-50%, -50%)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    pointerEvents: 'none',
                  }}
                >
                  {centerContent}
                </div>
              </div>
            </foreignObject>
          </g>
        )}

        <path
          d={BODY_PATH}
          fill="none"
          stroke="#9ab0c4"
          strokeWidth="5"
          strokeLinejoin="round"
          strokeLinecap="round"
        />
      </svg>
    </div>
  )
}
